/**
 * MedX table runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Data grid for inventory rows with sorting, filtering, and pagination hooks.
 */
const TABLE_COLUMNS = Object.freeze({
  inventory: [
    { key: "sku", label: "SKU", sortable: true, width: "120px" },
    { key: "name", label: "Product name", sortable: true },
    { key: "lot", label: "Lot #", sortable: true, width: "140px" },
    { key: "quantity", label: "Qty", sortable: true, align: "right", width: "80px" },
    { key: "warehouse", label: "Warehouse", sortable: true, width: "160px" },
    { key: "expiry", label: "Expiry", sortable: true, width: "110px" },
    { key: "status", label: "Status", sortable: true, width: "100px" },
  ],
  orders: [
    { key: "orderId", label: "Order ID", sortable: true, width: "120px" },
    { key: "supplier", label: "Supplier", sortable: true },
    { key: "items", label: "Items", sortable: true, align: "right", width: "80px" },
    { key: "total", label: "Total", sortable: true, align: "right", width: "100px" },
    { key: "status", label: "Status", sortable: true, width: "110px" },
    { key: "created", label: "Created", sortable: true, width: "110px" },
  ],
});

const SAMPLE_INVENTORY_ROWS = Object.freeze([
  { sku: "SKU-1042", name: "Influenza Vaccine 2026", lot: "LOT-A8F2K91M", quantity: 1200, warehouse: "East DC", expiry: "2026-11-30", status: "active" },
  { sku: "SKU-2088", name: "Surgical Masks (50/box)", lot: "LOT-B3D7H22P", quantity: 5000, warehouse: "Central Hub", expiry: "2028-06-15", status: "active" },
  { sku: "SKU-3011", name: "Insulin Pens 3ml", lot: "LOT-C1E9J44R", quantity: 340, warehouse: "West Cold", expiry: "2026-04-20", status: "active" },
  { sku: "SKU-4490", name: "IV Saline 500ml", lot: "LOT-D5G2L66T", quantity: 800, warehouse: "East DC", expiry: "2027-01-10", status: "active" },
  { sku: "SKU-5502", name: "Antibiotic Tablets", lot: "LOT-E7H4M88V", quantity: 0, warehouse: "APAC", expiry: "2025-12-01", status: "expired" },
]);

const tableInstances = new Map();

function createTable(config) {
  const id = config.id ?? `medx-table-${tableInstances.size + 1}`;
  const columns = TABLE_COLUMNS[config.schema] ?? config.columns ?? [];
  const instance = {
    id,
    schema: config.schema ?? "custom",
    columns,
    rows: [...(config.rows ?? SAMPLE_INVENTORY_ROWS)],
    sort: config.sort ?? { key: null, direction: "asc" },
    filter: config.filter ?? "",
    page: 1,
    pageSize: config.pageSize ?? 10,
    selectedRows: new Set(),
    onSort: typeof config.onSort === "function" ? config.onSort : null,
    onSelect: typeof config.onSelect === "function" ? config.onSelect : null,
  };
  tableInstances.set(id, instance);
  return instance;
}

function sortTable(id, columnKey) {
  const table = tableInstances.get(id);
  if (!table) return null;
  const col = table.columns.find((c) => c.key === columnKey);
  if (!col?.sortable) return null;

  if (table.sort.key === columnKey) {
    table.sort.direction = table.sort.direction === "asc" ? "desc" : "asc";
  } else {
    table.sort = { key: columnKey, direction: "asc" };
  }

  table.rows.sort((a, b) => {
    const av = a[columnKey];
    const bv = b[columnKey];
    if (av == null) return 1;
    if (bv == null) return -1;
    const cmp = typeof av === "number" ? av - bv : String(av).localeCompare(String(bv));
    return table.sort.direction === "asc" ? cmp : -cmp;
  });

  if (table.onSort) table.onSort(table.sort);
  return table.sort;
}

function filterTable(id, query) {
  const table = tableInstances.get(id);
  if (!table) return null;
  table.filter = String(query ?? "").trim().toLowerCase();
  return table.filter;
}

function getVisibleRows(id) {
  const table = tableInstances.get(id);
  if (!table) return [];
  let rows = table.rows;
  if (table.filter) {
    rows = rows.filter((row) =>
      Object.values(row).some((v) => String(v).toLowerCase().includes(table.filter)),
    );
  }
  const start = (table.page - 1) * table.pageSize;
  return rows.slice(start, start + table.pageSize);
}

function toggleRowSelection(id, rowIndex) {
  const table = tableInstances.get(id);
  if (!table) return false;
  if (table.selectedRows.has(rowIndex)) table.selectedRows.delete(rowIndex);
  else table.selectedRows.add(rowIndex);
  if (table.onSelect) table.onSelect(Array.from(table.selectedRows));
  return true;
}

async function runMedxTable() {
  console.log("[medx:ui:table] runtime initialized");
  console.log(`[medx:ui:table] schemas=${Object.keys(TABLE_COLUMNS).length}`);

  const inventoryTable = createTable({ schema: "inventory", pageSize: 5 });
  sortTable(inventoryTable.id, "quantity");
  filterTable(inventoryTable.id, "cold");
  toggleRowSelection(inventoryTable.id, 0);
  toggleRowSelection(inventoryTable.id, 2);

  const visible = getVisibleRows(inventoryTable.id);
  console.log(`[medx:ui:table] instances=${tableInstances.size}`);
  console.log(`[medx:ui:table] visibleRows=${visible.length} selected=${inventoryTable.selectedRows.size}`);
  console.log("[medx:ui:table] sort", inventoryTable.sort);
  console.log("[medx:ui:table] bootstrap complete");
}

module.exports = runMedxTable;
